mapper.select:
select *
from `gas_station_sale_data`
where `user_id` = #{userId}
and `effective` = true
order by `id` DESC

    limit #{startIndex},#{amount}

select *
from `gas_station_sale_data`

    and `id`=#{id}
    and `user_id`=#{userId}
    and `gas_station_id` = #{gasStationId}
    and `oil_type` =
        #{oilType,typeHandler=com.ruoyi.gas.module.price.mapper.handler.OilTypeHandler}

    and l_number = #{LNumber}
    and `kg_number` = #{KgNumber}
    and `price` = #{price}
    and `date` = #{date}
    and `batch` = #{batch}
    and `efffective` = TRUE;

select sum(`price`) / count(`price`)
from `gas_station_sale_data`
where `user_id` = #{userId}
  and `gas_station_id` = #{gasStationId}
  and `effective` = true
  and `oil_type` = #{oilType,typeHandler=com.ruoyi.gas.module.price.mapper.handler.OilTypeHandler}
  and `date` >= #{startTime,typeHandler=com.ruoyi.gas.module.price.mapper.handler.DateTimeHandler}
  and `date` <= #{endTime,typeHandler=com.ruoyi.gas.module.price.mapper.handler.DateTimeHandler};

select sum(`l_number`)
from `gas_station_sale_data`
where `user_id` = #{userId}
  and `gas_station_id` = #{gasStationId}
  and `effective` = true
  and `oil_type` = #{oilType,typeHandler=com.ruoyi.gas.module.price.mapper.handler.OilTypeHandler}
  and `date` >= #{startTime,typeHandler=com.ruoyi.gas.module.price.mapper.handler.DateTimeHandler}
  and `date` < #{endTime,typeHandler=com.ruoyi.gas.module.price.mapper.handler.DateTimeHandler};
